#include <stdio.h>
#include <pthread.h>
#include <stdbool.h>

volatile int turn;
volatile bool flag[2] = {false, false};
int shared_counter = 0;

void* process(void* arg) {
 int i = *(int*)arg;
 int j = 1 - i;

 for (int k = 0; k < 100000; k++) {
 // Entry section
 flag[i] = true;
 turn = j;
 while (flag[j] && turn == j); // Busy wait

 // Critical Section
 shared_counter++;

 // Exit section
 flag[i] = false;

 // Remainder section
 }
 return NULL;
}

int main() {
 pthread_t t0, t1;
 int id0 = 0, id1 = 1;

 pthread_create(&t0, NULL, process, &id0);
 pthread_create(&t1, NULL, process, &id1);

 pthread_join(t0, NULL);
 pthread_join(t1, NULL);

 printf("Final counter: %d (expected: 200000)\n", shared_counter);
 return 0;
}

public class PetersonLock {
 private volatile boolean[] flag = new boolean[2];
 private volatile int turn;

 public void lock(int i) {
 int j = 1 - i;
 flag[i] = true;
 turn = j;
 while (flag[j] && turn == j) {
 Thread.yield(); // Busy wait
 }
 }

 public void unlock(int i) {
 flag[i] = false;
 }

 // Test
 static int counter = 0;
 static PetersonLock lock = new PetersonLock();

 public static void main(String[] args) throws Exception {
 Thread t0 = new Thread(() -> {
 for (int i = 0; i < 100000; i++) {
 lock.lock(0);
 counter++;
 lock.unlock(0);
 }
 });

 Thread t1 = new Thread(() -> {
 for (int i = 0; i < 100000; i++) {
 lock.lock(1);
 counter++;
 lock.unlock(1);
 }
 });

 t0.start(); t1.start();
 t0.join(); t1.join();

 System.out.println("Counter: " + counter + " (expected: 200000)");
 }
}

