import threading
import ctypes

# Python doesn't have native atomic operations,
# but we can simulate the concept
class SpinLock:
 def __init__(self):
 self._lock = threading.Lock()
 self._locked = False

 def test_and_set(self):
 """Atomically tests and sets the lock."""
 with self._lock:
 old_value = self._locked
 self._locked = True
 return old_value

 def acquire(self):
 while self.test_and_set():
 pass # Spin

 def release(self):
 self._locked = False

# Usage
lock = SpinLock()
counter = 0

def worker():
 global counter
 for _ in range(100000):
 lock.acquire()
 counter += 1
 lock.release()

threads = [threading.Thread(target=worker) for _ in range(2)]
for t in threads: t.start()
for t in threads: t.join()

print(f"Counter: {counter}")

import java.util.concurrent.atomic.AtomicBoolean;

public class TestAndSetLock {
 private AtomicBoolean lock = new AtomicBoolean(false);

 public void acquire() {
 // Spin until we set lock from false to true
 while (lock.getAndSet(true)) {
 Thread.yield();
 }
 }

 public void release() {
 lock.set(false);
 }

 // Test
 static int counter = 0;
 static TestAndSetLock tas = new TestAndSetLock();

 public static void main(String[] args) throws Exception {
 Runnable task = () -> {
 for (int i = 0; i < 100000; i++) {
 tas.acquire();
 counter++;
 tas.release();
 }
 };

 Thread t1 = new Thread(task);
 Thread t2 = new Thread(task);

 t1.start(); t2.start();
 t1.join(); t2.join();

 System.out.println("Counter: " + counter);
 }
}
